 1→import type { ErrorHandler } from "hono";
 2→import * as Sentry from "@sentry/node";
 3→import { AppError } from "../lib/errors";
 4→
 5→export const errorHandler: ErrorHandler = (err, c) => {
 6→  if (err instanceof AppError) {
 7→    return c.json(
 8→      { error: err.message, ...(err.details ? { details: err.details } : {}) },
 9→      err.statusCode as any
10→    );
11→  }
12→
13→  Sentry.captureException(err);
14→  console.error("Unhandled error:", err);
15→  return c.json({ error: "Internal server error" }, 500);
16→};
