  1→// Query protocol — WebSocket wire format for the cloud relay.
  2→// All frame types prefixed with "q:" so they route cleanly in the ws.service dispatcher.
  3→//
  4→// Domain constants (QUERY_RESOURCES, MUTATION_NAMES, COMMAND_NAMES, PROTOCOL_EVENTS)
  5→// live in shared/events.ts — the single source of truth for all app events
  6→// and resources. This file only defines the wire format that carries them.
  7→
  8→import type { QueryResource, MutationName, CommandName, ProtocolEvent } from "../events";
  9→
 10→// Re-export so existing `import { QueryResource } from "query-protocol"` still works.
 11→export type { QueryResource, MutationName, CommandName, ProtocolEvent };
 12→export { QUERY_RESOURCES, MUTATION_NAMES, COMMAND_NAMES, PROTOCOL_EVENTS } from "../events";
 13→
 14→// ---- Client → Server Frames ----
 15→
 16→/** Client requests data (one-shot). */
 17→export interface QRequestFrame {
 18→  type: "q:request";
 19→  id: string;
 20→  resource: QueryResource;
 21→  params?: Record<string, unknown>;
 22→}
 23→
 24→/** Client subscribes to live updates for a resource. */
 25→export interface QSubscribeFrame {
 26→  type: "q:subscribe";
 27→  id: string;
 28→  resource: QueryResource;
 29→  params?: Record<string, unknown>;
 30→}
 31→
 32→/** Client unsubscribes by subscription ID (no resource/params needed). */
 33→export interface QUnsubscribeFrame {
 34→  type: "q:unsubscribe";
 35→  id: string;
 36→}
 37→
 38→/** Client requests a mutation. Field is `action`, not `mutation`. */
 39→export interface QMutateFrame {
 40→  type: "q:mutate";
 41→  id: string;
 42→  action: MutationName;
 43→  params: Record<string, unknown>;
 44→}
 45→
 46→/** Client sends an async command (e.g. sendMessage, stopSession). */
 47→export interface QCommandFrame {
 48→  type: "q:command";
 49→  id: string;
 50→  command: CommandName;
 51→  params: Record<string, unknown>;
 52→}
 53→
 54→/** Client responds to a tool relay request (q:event tool:request → q:tool_response). */
 55→export interface QToolResponseSuccessFrame {
 56→  type: "q:tool_response";
 57→  requestId: string;
 58→  result: unknown;
 59→  error?: never;
 60→}
 61→
 62→export interface QToolResponseErrorFrame {
 63→  type: "q:tool_response";
 64→  requestId: string;
 65→  error: string;
 66→  result?: never;
 67→}
 68→
 69→export type QToolResponseFrame = QToolResponseSuccessFrame | QToolResponseErrorFrame;
 70→
 71→/** All frames a client can send. */
 72→export type QClientFrame =
 73→  | QRequestFrame
 74→  | QSubscribeFrame
 75→  | QUnsubscribeFrame
 76→  | QMutateFrame
 77→  | QCommandFrame
 78→  | QToolResponseFrame;
 79→
 80→// ---- Server → Client Frames ----
 81→
 82→/** Server returns data for a one-shot request. */
 83→export interface QResponseFrame {
 84→  type: "q:response";
 85→  id: string;
 86→  data: unknown;
 87→}
 88→
 89→/** Server pushes a full snapshot to a subscriber (keyed by subscription ID). */
 90→export interface QSnapshotFrame {
 91→  type: "q:snapshot";
 92→  id: string;
 93→  data: unknown;
 94→  cursor?: number;
 95→}
 96→
 97→/** Server pushes incremental update (keyed by subscription ID). */
 98→export interface QDeltaFrame {
 99→  type: "q:delta";
100→  id: string;
101→  upserted?: unknown[];
102→  removed?: string[];
103→  cursor?: number;
104→}
105→
106→/** Server returns mutation result. Uses `success`, not `ok`. */
107→export interface QMutateResultFrame {
108→  type: "q:mutate_result";
109→  id: string;
110→  success: boolean;
111→  data?: unknown;
112→  error?: string;
113→}
114→
115→/** Server tells clients to refetch stale resources. */
116→export interface QInvalidateFrame {
117→  type: "q:invalidate";
118→  resources: QueryResource[];
119→}
120→
121→/** Server acknowledges an async command. */
122→export interface QCommandAckFrame {
123→  type: "q:command_ack";
124→  id: string;
125→  accepted: boolean;
126→  commandId?: string;
127→  error?: string;
128→}
129→
130→/** Server pushes an ephemeral event (no subscription needed). */
131→export interface QEventFrame {
132→  type: "q:event";
133→  event: ProtocolEvent;
134→  data: unknown;
135→}
136→
137→/** Server error for a specific request. */
138→export interface QErrorFrame {
139→  type: "q:error";
140→  id: string;
141→  code: string;
142→  message: string;
143→}
144→
145→/** All frames a server can send. */
146→export type QServerFrame =
147→  | QResponseFrame
148→  | QSnapshotFrame
149→  | QDeltaFrame
150→  | QMutateResultFrame
151→  | QCommandAckFrame
152→  | QEventFrame
153→  | QInvalidateFrame
154→  | QErrorFrame;
155→
156→// ---- Tool Relay Event Payload ----
157→
158→/** Payload shape for q:event with event: "tool:request".
159→ *  Sent by the backend when relaying a tool request from the agent to the frontend.
160→ *  Derived from the canonical ToolRequestEvent (shared/agent-events.ts) minus the
161→ *  discriminator field — the WS frame wraps this in q:event, not as a standalone event. */
162→export type ToolRequestEventData = Omit<import("../agent-events").ToolRequestEvent, "type">;
