  1→/**
  2→ * Hook that subscribes to a query protocol resource via WebSocket and writes
  3→ * snapshots/deltas directly into the React Query cache.
  4→ *
  5→ * This bypasses the HTTP refetch cycle: instead of
  6→ *   event -> invalidate -> HTTP GET -> render
  7→ * it becomes:
  8→ *   WS q:snapshot -> setQueryData -> render
  9→ *
 10→ * The HTTP queryFn remains as fallback for initial load (before WS connects).
 11→ */
 12→
 13→import { useEffect, useMemo, useRef, useState } from "react";
 14→import { useQueryClient, type QueryKey } from "@tanstack/react-query";
 15→import { subscribe, isConnected, onConnectionChange } from "@/platform/ws";
 16→import type { QueryResource } from "@shared/types/query-protocol";
 17→
 18→interface UseQuerySubscriptionOptions {
 19→  /** React Query cache key to write data into. */
 20→  queryKey: QueryKey;
 21→  /** Optional params passed to the backend query (e.g., { state: "ready,initializing" }). */
 22→  params?: Record<string, unknown>;
 23→  /** Disable the subscription (e.g., when data isn't needed). Defaults to true. */
 24→  enabled?: boolean;
 25→  /** Custom delta merge. Receives old cache value + delta items, returns new cache value.
 26→   *  When provided, replaces the default flat-array merge for q:delta frames. */
 27→  mergeDelta?: (old: unknown, upserted?: unknown[], removed?: string[]) => unknown;
 28→}
 29→
 30→/**
 31→ * Subscribe to a query protocol resource and write snapshots/deltas
 32→ * directly into the React Query cache.
 33→ *
 34→ * On q:snapshot: replaces the entire cache entry via setQueryData.
 35→ * On q:delta: merges upserted items and removes removed items (for list resources).
 36→ *
 37→ * IMPORTANT: queryKey must be a pure function of (resource, params). The queryKey
 38→ * is stored in a ref and not included in the subscription effect's dependency
 39→ * array — if queryKey drifts independently from params, the snapshot would write
 40→ * to the wrong cache entry.
 41→ */
 42→export function useQuerySubscription(
 43→  resource: QueryResource,
 44→  options: UseQuerySubscriptionOptions
 45→): void {
 46→  const { queryKey, params, enabled = true, mergeDelta } = options;
 47→  const queryClient = useQueryClient();
 48→
 49→  // Track WS connection state so the subscription effect re-runs when
 50→  // the connection comes up. Without this, hooks that mount before WS
 51→  // connects would return early and never subscribe (staleTime: Infinity
 52→  // means the HTTP fallback data would never refresh).
 53→  const [wsConnected, setWsConnected] = useState(isConnected());
 54→  useEffect(() => {
 55→    return onConnectionChange(setWsConnected);
 56→  }, []);
 57→
 58→  // Stable string key for params so effect doesn't re-run on referential changes
 59→  const stableParamsKey = useMemo(() => (params ? JSON.stringify(params) : ""), [params]);
 60→
 61→  // Use refs for callbacks to avoid re-subscribing on every render
 62→  const queryClientRef = useRef(queryClient);
 63→  queryClientRef.current = queryClient;
 64→
 65→  const queryKeyRef = useRef(queryKey);
 66→  queryKeyRef.current = queryKey;
 67→
 68→  const mergeDeltaRef = useRef(mergeDelta);
 69→  mergeDeltaRef.current = mergeDelta;
 70→
 71→  useEffect(() => {
 72→    if (!enabled || !wsConnected) return;
 73→
 74→    const unsubscribe = subscribe(
 75→      resource,
 76→      params,
 77→      // onSnapshot: replace entire cache entry
 78→      (data) => {
 79→        queryClientRef.current.setQueryData(queryKeyRef.current, data);
 80→      },
 81→      // onDelta: merge incremental updates (for list resources like messages)
 82→      (upserted, removed) => {
 83→        if (!upserted && !removed) return;
 84→
 85→        queryClientRef.current.setQueryData(queryKeyRef.current, (old: unknown) => {
 86→          // Custom merge strategy (e.g., PaginatedMessages for message cache)
 87→          if (mergeDeltaRef.current) {
 88→            return mergeDeltaRef.current(old, upserted, removed);
 89→          }
 90→
 91→          // Default: flat array merge
 92→          if (!Array.isArray(old)) return old;
 93→
 94→          let result = [...old];
 95→
 96→          // Remove items by ID
 97→          if (removed && removed.length > 0) {
 98→            const removeSet = new Set(removed);
 99→            result = result.filter(
100→              (item: unknown) =>
101→                !(
102→                  typeof item === "object" &&
103→                  item !== null &&
104→                  "id" in item &&
105→                  removeSet.has((item as { id: string }).id)
106→                )
107→            );
108→          }
109→
110→          // Upsert items (update existing or append new)
111→          if (upserted && upserted.length > 0) {
112→            for (const item of upserted) {
113→              if (typeof item !== "object" || item === null || !("id" in item)) {
114→                result.push(item);
115→                continue;
116→              }
117→              const itemId = (item as { id: string }).id;
118→              const idx = result.findIndex(
119→                (existing: unknown) =>
120→                  typeof existing === "object" &&
121→                  existing !== null &&
122→                  "id" in existing &&
123→                  (existing as { id: string }).id === itemId
124→              );
125→              if (idx >= 0) {
126→                result[idx] = item;
127→              } else {
128→                result.push(item);
129→              }
130→            }
131→          }
132→
133→          return result;
134→        });
135→      }
136→    );
137→
138→    return unsubscribe;
139→    // eslint-disable-next-line react-hooks/exhaustive-deps
140→  }, [resource, enabled, stableParamsKey, wsConnected]);
141→}
142→

  1→/**
  2→ * Workspace Query Hooks
  3→ * TanStack Query hooks for workspace-related data fetching
  4→ */
  5→
  6→import { useQuery, useMutation, useQueryClient, keepPreviousData } from "@tanstack/react-query";
  7→import { useMemo } from "react";
  8→import { produce } from "immer";
  9→import { WorkspaceService } from "./workspace.service";
 10→import { RepoService } from "@/features/repository/api/repository.service";
 11→import { queryKeys } from "@/shared/api/queryKeys";
 12→import { useQuerySubscription } from "@/shared/hooks/useQuerySubscription";
 13→import type { RepoGroup, DiffStats } from "../types";
 14→import type { PRStatus } from "@/shared/types";
 15→import { createOptimisticWorkspace, mergeWorkspaceDelta } from "../lib/workspace.utils";
 16→import { track } from "@/platform/analytics";
 17→
 18→/**
 19→ * Fetch workspaces grouped by repository.
 20→ *
 21→ * WS subscription pushes data directly into cache via q:snapshot.
 22→ * HTTP queryFn is fallback for initial load before WS connects.
 23→ * Event-driven invalidation via IPC events also works (both paths coexist).
 24→ */
 25→export function useWorkspacesByRepo(state: string = "ready,initializing") {
 26→  useQuerySubscription("workspaces", {
 27→    queryKey: queryKeys.workspaces.byRepo(state),
 28→    params: { state },
 29→    mergeDelta: mergeWorkspaceDelta,
 30→  });
 31→
 32→  return useQuery({
 33→    queryKey: queryKeys.workspaces.byRepo(state),
 34→    queryFn: () => WorkspaceService.fetchByRepo(state),
 35→    staleTime: Infinity, // WS subscription keeps data fresh
 36→    refetchOnWindowFocus: false, // Subscription handles freshness
 37→  });
 38→}
 39→
 40→/**
 41→ * Fetch global stats.
 42→ *
 43→ * WS subscription pushes data directly into cache via q:snapshot.
 44→ * HTTP queryFn is fallback for initial load before WS connects.
 45→ */
 46→export function useStats() {
 47→  useQuerySubscription("stats", {
 48→    queryKey: queryKeys.stats.all,
 49→  });
 50→
 51→  return useQuery({
 52→    queryKey: queryKeys.stats.all,
 53→    queryFn: () => RepoService.fetchStats(),
 54→    staleTime: Infinity, // WS subscription keeps data fresh
 55→    refetchOnWindowFocus: false, // Subscription handles freshness
 56→  });
 57→}
 58→
 59→/**
 60→ * Fetch diff stats for a specific workspace
 61→ * Conditionally polls only when workspace is actively working.
 62→ *
 63→ * When `isWatched` is true (file watcher active via notify crate),
 64→ * polling is disabled — cache invalidation comes from fs:changed events.
 65→ * Falls back to 5s polling when not watched.
 66→ *
 67→ * IMPORTANT: Requires workspaceState === "ready" to avoid fetching diffs
 68→ * against incomplete worktrees during initialization. Running git diff on
 69→ * an initializing worktree produces garbage (e.g. +500K/-1M) that gets
 70→ * cached for 30s, persisting as phantom diffs even after the workspace
 71→ * becomes ready. Guard here, not in the UI.
 72→ */
 73→export function useDiffStats(
 74→  workspaceId: string | null,
 75→  sessionStatus?: string | null,
 76→  isWatched: boolean = false,
 77→  workspaceState?: string | null
 78→) {
 79→  return useQuery({
 80→    queryKey: queryKeys.workspaces.diffStats(workspaceId || ""),
 81→    queryFn: () => WorkspaceService.fetchDiffStats(workspaceId!),
 82→    enabled: !!workspaceId && workspaceState === "ready",
 83→    staleTime: 30000,
 84→    // Events handle invalidation when watched; fall back to polling otherwise
 85→    refetchInterval: isWatched ? false : sessionStatus === "working" ? 5000 : false,
 86→    refetchOnMount: "always",
 87→    refetchOnWindowFocus: true,
 88→  });
 89→}
 90→
 91→/**
 92→ * Fetch diff stats for all sidebar workspaces in bulk.
 93→ *
 94→ * Replaces per-item useDiffStats() in the sidebar (N hooks → 1 query).
 95→ * - Initial load: fetches ALL ready workspaces in parallel batches of 15
 96→ * - Polling: only re-fetches workspaces with session_status === "working" (5s)
 97→ * - Idle: no polling (staleTime 30s, refetch on window focus)
 98→ * - On workspace list change: seeds from per-workspace cache, fetches only missing/working
 99→ *
100→ * Guard: state === "ready" — initializing worktrees have incomplete git state
101→ * (missing HEAD, partial index → garbage diffs like +500K/-1M). Setup script
102→ * diffs are fine — .gitignore handles them, and `git checkout -- .` in the
103→ * init pipeline resets any tracked-file mutations from bun install.
104→ */
105→export function useBulkDiffStats(repoGroups: RepoGroup[]) {
106→  const queryClient = useQueryClient();
107→
108→  // Stable, de-duplicated IDs for query key — only ready workspaces.
109→  const workspaceIds = useMemo(() => {
110→    const ids = repoGroups.flatMap((g) =>
111→      g.workspaces.filter((w) => w.state === "ready").map((w) => w.id)
112→    );
113→    return Array.from(new Set(ids)).sort();
114→  }, [repoGroups]);
115→
116→  // IDs of workspaces with active sessions — only these need polling.
117→  const workingIds = useMemo(() => {
118→    return repoGroups
119→      .flatMap((g) => g.workspaces)
120→      .filter((w) => w.state === "ready" && w.session_status === "working")
121→      .map((w) => w.id);
122→  }, [repoGroups]);
123→
124→  const hasWorkingWorkspaces = workingIds.length > 0;
125→
126→  return useQuery({
127→    queryKey: ["bulk-diff-stats", workspaceIds],
128→    enabled: workspaceIds.length > 0,
129→    staleTime: 30_000,
130→    placeholderData: keepPreviousData,
131→    refetchInterval: hasWorkingWorkspaces ? 5000 : false,
132→    refetchOnMount: "always",
133→    refetchOnWindowFocus: true,
134→    queryFn: async () => {
135→      // Seed from per-workspace cache for workspaces we already have data for
136→      const results: Record<string, DiffStats> = {};
137→      for (const id of workspaceIds) {
138→        const cached = queryClient.getQueryData<DiffStats>(queryKeys.workspaces.diffStats(id));
139→        if (cached) results[id] = cached;
140→      }
141→
142→      // Fetch: missing workspaces + working workspaces (need fresh data)
143→      const missingIds = workspaceIds.filter((id) => !(id in results));
144→      const idsToFetch = [...new Set([...missingIds, ...workingIds])];
145→
146→      if (idsToFetch.length === 0) return results;
147→
148→      // Parallel batches of 15 — balances throughput vs resource pressure
149→      const BATCH_SIZE = 15;
150→      for (let i = 0; i < idsToFetch.length; i += BATCH_SIZE) {
151→        const batch = idsToFetch.slice(i, i + BATCH_SIZE);
152→        const settled = await Promise.allSettled(
153→          batch.map((id) => WorkspaceService.fetchDiffStats(id))
154→        );
155→
156→        batch.forEach((id, j) => {
157→          if (settled[j].status === "fulfilled") {
158→            results[id] = settled[j].value;
159→            queryClient.setQueryData(queryKeys.workspaces.diffStats(id), settled[j].value);
160→          }
161→        });
162→      }
163→
164→      return results;
165→    },
166→  });
167→}
