260→/**
261→ * Fetch PR status for a workspace.
262→ *
263→ * Gated on gh CLI being installed + authenticated (like Codex).
264→ * Polls every 30s while agent is working (to detect PR creation),
265→ * 60s while CI is pending post-session (CI runs 2-15min after push),
266→ * stops polling otherwise.
267→ */
268→export function usePRStatus(
269→  workspaceId: string | null,
270→  options?: { ghInstalled?: boolean; ghAuthenticated?: boolean; sessionStatus?: string }
271→) {
272→  const { ghInstalled = true, ghAuthenticated = true, sessionStatus } = options ?? {};
273→  return useQuery({
274→    queryKey: queryKeys.workspaces.prStatus(workspaceId || ""),
275→    queryFn: () => WorkspaceService.fetchPRStatus(workspaceId!),
276→    enabled: !!workspaceId && ghInstalled && ghAuthenticated,
277→    staleTime: 10_000,
278→    refetchInterval: (query) => {
279→      // While agent is working: poll every 30s to detect PR creation/updates.
280→      if (sessionStatus === "working") return 30_000;
281→
282→      // After agent stops: CI checks typically run 2-15min. Poll every 60s
283→      // while CI is pending so the user sees updates without manual refresh.
284→      const data = query.state.data as PRStatus | null | undefined;
285→      if (data?.has_pr && data?.ci_status === "pending") return 60_000;
286→
287→      // No PR or CI resolved: stop polling. Window focus refetch handles edge cases.
288→      return false;
289→    },
290→    refetchOnWindowFocus: true,
291→  });
292→}
