309→/**
310→ * Create workspace mutation with optimistic update.
311→ *
312→ * Flow:
313→ * 1. User clicks "+" → placeholder workspace appears instantly in sidebar
314→ * 2. Backend creates workspace (state = "initializing"), returns it
315→ * 3. onSuccess replaces placeholder with real data, triggers refetch
316→ * 4. Workspace progress events + terminal invalidation catch the ready transition
317→ */
318→export function useCreateWorkspace() {
319→  const queryClient = useQueryClient();
320→  const queryKey = queryKeys.workspaces.byRepo("ready,initializing");
321→
322→  return useMutation({
323→    mutationFn: (repositoryId: string) => WorkspaceService.create(repositoryId),
324→
325→    onMutate: async (repositoryId: string) => {
326→      await queryClient.cancelQueries({ queryKey });
327→
328→      const previousData = queryClient.getQueryData<RepoGroup[]>(queryKey);
329→
330→      // Inject a placeholder workspace into the matching repo group
331→      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
332→        if (!old) return old;
333→        return produce(old, (draft) => {
334→          const repoGroup = draft.find((g) => g.repo_id === repositoryId);
335→          if (repoGroup) {
336→            repoGroup.workspaces.unshift(
337→              createOptimisticWorkspace(repositoryId, repoGroup.repo_name)
338→            );
339→          }
340→        });
341→      });
342→
343→      return { previousData };
344→    },
345→
346→    onError: (_err, _repositoryId, context) => {
347→      if (context?.previousData) {
348→        queryClient.setQueryData(queryKey, context.previousData);
349→      }
350→    },
351→
352→    onSuccess: (_data, repositoryId) => {
353→      track("workspace_created", { repository_id: repositoryId });
354→    },
355→
356→    onSettled: () => {
357→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
358→    },
359→  });
360→}
