  1→// sidecar/health.ts
  2→// Health endpoint handler and graceful shutdown coordinator for the agent-server.
  3→//
  4→// Health: GET /health returns uptime, memory, agents, connections.
  5→// Readiness: GET /readyz returns 200 if agents are initialized, 503 if not.
  6→// Graceful shutdown: drains in-flight turns before closing connections.
  7→
  8→import type { IncomingMessage, ServerResponse } from "http";
  9→import type { WebSocketServer } from "ws";
 10→import { getRegisteredAgentTypes, getAgent } from "./agents/registry";
 11→import type { AgentType } from "@shared/enums";
 12→import { EventBroadcaster } from "./event-broadcaster";
 13→
 14→// ============================================================================
 15→// Types
 16→// ============================================================================
 17→
 18→export interface HealthResponse {
 19→  status: "ok";
 20→  uptime: number;
 21→  memoryMb: number;
 22→  agents: string[];
 23→  connections: number;
 24→  version: string;
 25→  timestamp: string;
 26→}
 27→
 28→export interface ShutdownConfig {
 29→  /** Maximum time (ms) to wait for in-flight turns to drain. Default: 30_000 */
 30→  drainTimeoutMs: number;
 31→}
 32→
 33→const DEFAULT_SHUTDOWN_CONFIG: ShutdownConfig = {
 34→  drainTimeoutMs: 30_000,
 35→};
 36→
 37→// ============================================================================
 38→// Module state
 39→// ============================================================================
 40→
 41→/** Set to true once agents have been initialized */
 42→let agentsInitialized = false;
 43→
 44→/** Set to true when shutdown has been signaled */
 45→let shuttingDown = false;
 46→
 47→/** Active sessions (sessionId -> agentType). Add on turn/start, remove on idle/error/cancelled. */
 48→const activeSessions = new Map<string, string>();
 49→
 50→/** Process start time, used for uptime calculation */
 51→const startTime = Date.now();
 52→
 53→// ============================================================================
 54→// State accessors (exported for index.ts and tests)
 55→// ============================================================================
 56→
 57→export function setAgentsInitialized(value: boolean): void {
 58→  agentsInitialized = value;
 59→}
 60→
 61→export function isAgentsInitialized(): boolean {
 62→  return agentsInitialized;
 63→}
 64→
 65→export function isShuttingDown(): boolean {
 66→  return shuttingDown;
 67→}
 68→
 69→export function setShuttingDown(value: boolean): void {
 70→  shuttingDown = value;
 71→}
 72→
 73→export function getActiveSessions(): Map<string, string> {
 74→  return activeSessions;
 75→}
 76→
 77→export function trackSession(sessionId: string, agentType: string): void {
 78→  activeSessions.set(sessionId, agentType);
 79→}
 80→
 81→export function untrackSession(sessionId: string): void {
 82→  activeSessions.delete(sessionId);
 83→}
 84→
 85→export function getActiveSessionCount(): number {
 86→  return activeSessions.size;
 87→}
 88→
 89→// ============================================================================
 90→// Health endpoint handler
 91→// ============================================================================
 92→
 93→/**
 94→ * Builds the health response payload.
 95→ * Separated from the HTTP handler so it can be tested independently.
 96→ */
 97→export function buildHealthResponse(wss: WebSocketServer | null): HealthResponse {
 98→  const uptimeSeconds = (Date.now() - startTime) / 1000;
 99→  const memoryMb = Math.round((process.memoryUsage.rss() / 1024 / 1024) * 100) / 100;
100→  const agents = getRegisteredAgentTypes();
101→  const connections = wss ? wss.clients.size : 0;
102→
103→  return {
104→    status: "ok",
105→    uptime: Math.round(uptimeSeconds * 100) / 100,
106→    memoryMb,
107→    agents,
108→    connections,
109→    version: "1.0.0",
110→    timestamp: new Date().toISOString(),
111→  };
112→}
113→
114→/**
115→ * HTTP request handler for the agent-server.
116→ * Handles GET /health, GET /readyz, and returns 404 for everything else.
117→ * Non-GET requests and WebSocket upgrades are not routed here.
118→ */
119→export function handleHttpRequest(
120→  req: IncomingMessage,
121→  res: ServerResponse,
122→  wss: WebSocketServer | null
123→): void {
124→  const url = req.url || "/";
125→  const method = req.method || "GET";
126→
127→  if (method === "GET" && url === "/health") {
128→    const body = JSON.stringify(buildHealthResponse(wss));
129→    res.writeHead(200, {
130→      "Content-Type": "application/json",
131→      "Cache-Control": "no-store",
132→    });
133→    res.end(body);
134→    return;
135→  }
136→
137→  if (method === "GET" && url === "/readyz") {
138→    if (agentsInitialized && !shuttingDown) {
139→      res.writeHead(200, { "Content-Type": "application/json" });
140→      res.end(JSON.stringify({ status: "ready" }));
141→    } else {
142→      const reason = shuttingDown ? "shutting down" : "agents not initialized";
143→      res.writeHead(503, { "Content-Type": "application/json" });
144→      res.end(JSON.stringify({ status: "not ready", reason }));
145→    }
146→    return;
147→  }
148→
149→  // Everything else: 404 (WebSocket upgrades are handled separately by the WS server)
150→  res.writeHead(404, { "Content-Type": "text/plain" });
151→  res.end("Not Found");
152→}
153→
154→// ============================================================================
155→// Graceful shutdown with turn draining
156→// ============================================================================
157→
158→/**
159→ * Waits for all active sessions to complete, up to the configured timeout.
160→ * Returns true if all sessions drained, false if timeout was reached.
161→ */
162→export function waitForDrain(config: ShutdownConfig = DEFAULT_SHUTDOWN_CONFIG): Promise<boolean> {
163→  return new Promise((resolve) => {
164→    if (activeSessions.size === 0) {
165→      resolve(true);
166→      return;
167→    }
168→
169→    const deadline = Date.now() + config.drainTimeoutMs;
170→
171→    const checkInterval = setInterval(() => {
172→      if (activeSessions.size === 0) {
173→        clearInterval(checkInterval);
174→        resolve(true);
175→        return;
176→      }
177→
178→      if (Date.now() >= deadline) {
179→        clearInterval(checkInterval);
180→        resolve(false);
181→        return;
182→      }
183→    }, 100);
184→  });
185→}
186→
187→/**
188→ * Cancels all remaining active sessions using the proper cancellation flow.
189→ * Tries agent.cancel() first (which sets cancelledByUser, creates checkpoints,
190→ * and terminates subprocesses), then falls back to direct event emission.
191→ */
192→export async function cancelRemainingSessions(): Promise<void> {
193→  const entries = [...activeSessions];
194→  for (const [sessionId, agentType] of entries) {
195→    console.log(`[SHUTDOWN] Force-cancelling session ${sessionId} (agent=${agentType})`);
196→    const agent = getAgent(agentType as AgentType);
197→    if (agent) {
198→      try {
199→        await agent.cancel(sessionId);
200→      } catch (err) {
201→        console.error(
202→          `[SHUTDOWN] agent.cancel() failed for ${sessionId}, emitting events directly:`,
203→          err
204→        );
205→        EventBroadcaster.emitMessageCancelled(sessionId, agentType as any);
206→        EventBroadcaster.emitSessionCancelled(sessionId, agentType as any);
207→      }
208→    } else {
209→      EventBroadcaster.emitMessageCancelled(sessionId, agentType as any);
210→      EventBroadcaster.emitSessionCancelled(sessionId, agentType as any);
211→    }
212→  }
213→  activeSessions.clear();
214→}
215→
216→// ============================================================================
217→// Reset (for tests)
218→// ============================================================================
219→
220→export function resetHealthState(): void {
221→  agentsInitialized = false;
222→  shuttingDown = false;
223→  activeSessions.clear();
224→}
225→

  1→// backend/src/services/agent/persistence.ts
  2→// Database write functions for persisting canonical agent events.
  3→//
  4→// Adapted from sidecar/db/session-writer.ts. Key differences:
  5→// - Uses backend's getDatabase() (not sidecar's)
  6→// - No notifyBackend() calls (backend handles WS push via invalidate())
  7→// - No FrontendClient calls (backend pushes via query-engine directly)
  8→// - Takes event objects instead of positional args
  9→//
 10→// All functions are synchronous (better-sqlite3 is synchronous).
 11→// Callers (event-handler.ts) call invalidate() after persistence succeeds.
 12→
 13→import { getDatabase } from "../../lib/database";
 14→import { uuidv7 } from "@shared/lib/uuid";
 15→import { getErrorMessage } from "@shared/lib/errors";
 16→import type {
 17→  MessageAssistantEvent,
 18→  MessageToolResultEvent,
 19→  MessageResultEvent,
 20→  MessageCancelledEvent,
 21→  SessionStartedEvent,
 22→  SessionIdleEvent,
 23→  SessionErrorEvent,
 24→  SessionCancelledEvent,
 25→  AgentSessionIdEvent,
 26→} from "@shared/agent-events";
 27→
 28→// ============================================================================
 29→// WriteResult type (mirrors sidecar's pattern)
 30→// ============================================================================
 31→
 32→export type WriteResult<T = string> = { ok: true; value: T } | { ok: false; error: string };
 33→
 34→// ============================================================================
 35→// Message writes
 36→// ============================================================================
 37→
 38→/**
 39→ * Save an assistant message to the messages table.
 40→ * Mirrors sidecar saveAssistantMessage() logic:
 41→ * - Generates a local UUID7 message ID
 42→ * - Stores flat content array, except for cancelled messages which get an envelope
 43→ * - Records the agent_message_id and parent_tool_use_id for linking
 44→ */
 45→export function persistAssistantMessage(event: MessageAssistantEvent): WriteResult {
 46→  const db = getDatabase();
 47→  const messageId = uuidv7();
 48→  const sentAt = new Date().toISOString();
 49→
 50→  // Store flat content array for normal messages. For "cancelled" messages,
 51→  // write envelope so the frontend can detect cancellation from DB content.
 52→  const contentPayload =
 53→    event.message.stop_reason === "cancelled"
 54→      ? { message: { stop_reason: "cancelled" }, blocks: event.message.content ?? [] }
 55→      : (event.message.content ?? []);
 56→  const content = JSON.stringify(contentPayload);
 57→
 58→  try {
 59→    db.prepare(
 60→      `INSERT INTO messages (id, session_id, role, content, sent_at, model, agent_message_id, parent_tool_use_id)
 61→       VALUES (?, ?, 'assistant', ?, ?, ?, ?, ?)`
 62→    ).run(
 63→      messageId,
 64→      event.sessionId,
 65→      content,
 66→      sentAt,
 67→      event.model || null,
 68→      event.message.id || null,
 69→      event.message.parent_tool_use_id || null
 70→    );
 71→    return { ok: true, value: messageId };
 72→  } catch (error) {
 73→    const msg = getErrorMessage(error);
 74→    console.error(`[AgentPersistence] Failed to save assistant message:`, msg);
 75→    return { ok: false, error: msg };
 76→  }
 77→}
 78→
 79→/**
 80→ * Save a tool_result message (role='user') to the messages table.
 81→ * These contain tool execution results that link tool_use blocks to their outputs.
 82→ */
 83→export function persistToolResultMessage(event: MessageToolResultEvent): WriteResult {
 84→  const db = getDatabase();
 85→  const messageId = uuidv7();
 86→  const sentAt = new Date().toISOString();
 87→  const content = JSON.stringify(event.message.content ?? []);
 88→
 89→  try {
 90→    db.prepare(
 91→      `INSERT INTO messages (id, session_id, role, content, sent_at, agent_message_id, parent_tool_use_id)
 92→       VALUES (?, ?, 'user', ?, ?, ?, ?)`
 93→    ).run(
 94→      messageId,
 95→      event.sessionId,
 96→      content,
 97→      sentAt,
 98→      event.message.id || null,
 99→      event.message.parent_tool_use_id || null
100→    );
101→    return { ok: true, value: messageId };
102→  } catch (error) {
103→    const msg = getErrorMessage(error);
104→    console.error(`[AgentPersistence] Failed to save tool_result message:`, msg);
105→    return { ok: false, error: msg };
106→  }
107→}
108→
109→/**
110→ * Handle message.result events. No DB write needed — this is informational
111→ * (success/error_during_execution subtypes). Session status transitions are
112→ * handled by separate session.idle / session.error events.
113→ */
114→export function persistMessageResult(_event: MessageResultEvent): void {
115→  // No-op: message.result is informational only.
116→  // Session status is managed by session.idle / session.error events.
117→}
118→
119→/**
120→ * Persist a cancellation: insert a cancelled assistant message marker
121→ * and set session status to idle.
122→ *
123→ * The cancelled message uses the envelope format so the frontend can detect
124→ * cancellation on reload (the "Turn interrupted" label in AssistantTurn).
125→ */
126→export function persistMessageCancelled(event: MessageCancelledEvent): WriteResult {
127→  const db = getDatabase();
128→  const messageId = uuidv7();
129→  const sentAt = new Date().toISOString();
130→
131→  // Empty cancelled message with envelope so frontend detects cancellation
132→  const content = JSON.stringify({
133→    message: { stop_reason: "cancelled" },
134→    blocks: [],
135→  });
136→
137→  try {
138→    db.transaction(() => {
139→      db.prepare(
140→        `INSERT INTO messages (id, session_id, role, content, sent_at, cancelled_at)
141→         VALUES (?, ?, 'assistant', ?, ?, ?)`
142→      ).run(messageId, event.sessionId, content, sentAt, sentAt);
143→
144→      db.prepare(
145→        `UPDATE sessions SET status = 'idle', error_message = NULL, error_category = NULL, updated_at = datetime('now') WHERE id = ?`
146→      ).run(event.sessionId);
147→    })();
148→
149→    return { ok: true, value: messageId };
150→  } catch (error) {
151→    const msg = getErrorMessage(error);
152→    console.error(`[AgentPersistence] Failed to persist message.cancelled:`, msg);
153→    return { ok: false, error: msg };
154→  }
155→}
156→
157→// ============================================================================
158→// Session status writes
159→// ============================================================================
160→
161→/**
162→ * Update session status to "working" when a turn starts.
163→ * Only updates if the session is not already working (idempotent).
164→ */
165→export function persistSessionStarted(event: SessionStartedEvent): WriteResult<void> {
166→  const db = getDatabase();
167→
168→  try {
169→    db.prepare(
170→      `UPDATE sessions SET status = 'working', error_message = NULL, error_category = NULL, updated_at = datetime('now')
171→       WHERE id = ? AND status != 'working'`
172→    ).run(event.sessionId);
173→    return { ok: true, value: undefined };
174→  } catch (error) {
175→    const msg = getErrorMessage(error);
176→    console.error(`[AgentPersistence] Failed to persist session.started:`, msg);
177→    return { ok: false, error: msg };
178→  }
179→}
180→
181→/** Update session status to "idle" when a turn completes. */
182→export function persistSessionIdle(event: SessionIdleEvent): WriteResult<void> {
183→  const db = getDatabase();
184→
185→  try {
186→    db.prepare(
187→      `UPDATE sessions SET status = 'idle', error_message = NULL, error_category = NULL, updated_at = datetime('now') WHERE id = ?`
188→    ).run(event.sessionId);
189→    return { ok: true, value: undefined };
190→  } catch (error) {
191→    const msg = getErrorMessage(error);
192→    console.error(`[AgentPersistence] Failed to persist session.idle:`, msg);
193→    return { ok: false, error: msg };
194→  }
195→}
196→
197→/** Update session status to "error" with error details. */
198→export function persistSessionError(event: SessionErrorEvent): WriteResult<void> {
199→  const db = getDatabase();
200→
201→  try {
202→    db.prepare(
203→      `UPDATE sessions SET status = 'error', error_message = ?, error_category = ?, updated_at = datetime('now') WHERE id = ?`
204→    ).run(event.error, event.category, event.sessionId);
205→    return { ok: true, value: undefined };
206→  } catch (error) {
207→    const msg = getErrorMessage(error);
208→    console.error(`[AgentPersistence] Failed to persist session.error:`, msg);
209→    return { ok: false, error: msg };
210→  }
211→}
212→
213→/** Update session status after cancellation (back to idle). */
214→export function persistSessionCancelled(event: SessionCancelledEvent): WriteResult<void> {
215→  const db = getDatabase();
216→
217→  try {
218→    db.prepare(
219→      `UPDATE sessions SET status = 'idle', error_message = NULL, error_category = NULL, updated_at = datetime('now') WHERE id = ?`
220→    ).run(event.sessionId);
221→    return { ok: true, value: undefined };
222→  } catch (error) {
223→    const msg = getErrorMessage(error);
224→    console.error(`[AgentPersistence] Failed to persist session.cancelled:`, msg);
225→    return { ok: false, error: msg };
226→  }
227→}
228→
229→// ============================================================================
230→// Metadata writes
231→// ============================================================================
232→
233→/** Store the agent-provider session ID for resume support. */
234→export function persistAgentSessionId(event: AgentSessionIdEvent): WriteResult<void> {
235→  const db = getDatabase();
236→
237→  try {
238→    db.prepare(
239→      `UPDATE sessions SET agent_session_id = ?, updated_at = datetime('now') WHERE id = ?`
240→    ).run(event.agentSessionId, event.sessionId);
241→    return { ok: true, value: undefined };
242→  } catch (error) {
243→    const msg = getErrorMessage(error);
244→    console.error(`[AgentPersistence] Failed to persist agent.session_id:`, msg);
245→    return { ok: false, error: msg };
246→  }
247→}
