 1→import * as Sentry from "@sentry/react";
 2→import { track } from "@/platform/analytics";
 3→type ErrorContext = {
 4→  source?: string;
 5→  action?: string;
 6→  tags?: Record<string, string | number | boolean>;
 7→  extra?: Record<string, unknown>;
 8→};
 9→
10→function safeStringify(value: unknown): string {
11→  try {
12→    return JSON.stringify(value);
13→  } catch {
14→    return String(value);
15→  }
16→}
17→
18→export function normalizeError(error: unknown): Error {
19→  if (error instanceof Error) {
20→    return error;
21→  }
22→
23→  if (typeof error === "string") {
24→    return new Error(error);
25→  }
26→
27→  if (error && typeof error === "object") {
28→    const maybeMessage = (error as { message?: unknown }).message;
29→    if (typeof maybeMessage === "string") {
30→      return new Error(maybeMessage);
31→    }
32→  }
33→
34→  return new Error(safeStringify(error));
35→}
36→
37→export function reportError(error: unknown, context: ErrorContext = {}): Error {
38→  const normalized = normalizeError(error);
39→  const payload = {
40→    ...context,
41→    error: {
42→      name: normalized.name,
43→      message: normalized.message,
44→      stack: normalized.stack,
45→    },
46→  };
47→
48→  console.error("[Error]", payload);
49→
50→  Sentry.captureException(normalized, {
51→    tags: context.tags,
52→    extra: { ...context.extra, source: context.source, action: context.action },
53→  });
54→
55→  // Track errors in PostHog for reliability monitoring
56→  track("error_occurred", {
57→    source: context.source ?? "unknown",
58→    error_message: normalized.message.substring(0, 200),
59→  });
60→
61→  return normalized;
62→}
