38→/**
39→ * Merge a workspace delta (q:delta) into the existing RepoGroup[] cache.
40→ * Replaces matching workspaces by ID within their repo group, or appends if new.
41→ * Used by useQuerySubscription's mergeDelta option.
42→ */
43→export function mergeWorkspaceDelta(
44→  old: unknown,
45→  upserted?: unknown[],
46→  removed?: string[]
47→): unknown {
48→  if (!Array.isArray(old)) return old;
49→  const groups = old as RepoGroup[];
50→  if (!upserted && !removed) return old;
51→
52→  let result = groups.map((g) => ({ ...g, workspaces: [...g.workspaces] }));
53→
54→  if (removed?.length) {
55→    const removeSet = new Set(removed);
56→    result = result.map((g) => ({
57→      ...g,
58→      workspaces: g.workspaces.filter((w) => !removeSet.has(w.id)),
59→    }));
60→  }
61→
62→  if (upserted?.length) {
63→    for (const item of upserted) {
64→      const ws = item as Workspace;
65→      const group = result.find((g) => g.repo_id === ws.repository_id);
66→      if (!group) continue;
67→      const idx = group.workspaces.findIndex((w) => w.id === ws.id);
68→      if (idx >= 0) {
69→        group.workspaces[idx] = ws;
70→      } else {
71→        group.workspaces.push(ws);
72→      }
73→    }
74→  }
75→
76→  return result;
77→}
