243→    const staleWs = ws;
244→    ws = null;
245→    connected = false;
246→    connecting = false;
247→    _connectionId = null;
248→    staleWs.onclose = null;
249→    staleWs.close();
250→
251→    notifyConnectionChange(false);
252→  }
253→
254→  // Immediately open a new socket (reads fresh port from getBackendPort())
255→  connecting = true;
256→  openSocket().catch(() => {
257→    connecting = false;
258→    // If this fails, fall back to normal backoff reconnect
259→    scheduleReconnect();
260→  });
