276→// ---- Internal ----
277→
278→async function openSocket(): Promise<void> {
279→  const port = await getBackendPort();
280→  const url = `ws://localhost:${port}/ws`;
281→
282→  ws = new WebSocket(url);
283→
284→  ws.onopen = () => {
285→    // Localhost connections are auto-authenticated by the backend.
286→    // Wait for the "connected" frame in onmessage.
287→  };
288→
289→  ws.onmessage = (evt) => {
290→    let msg: Record<string, unknown>;
291→    try {
292→      msg = JSON.parse(evt.data as string);
293→    } catch {
294→      return;
295→    }
296→
297→    const type = typeof msg.type === "string" ? msg.type : "";
298→
299→    match(type)
300→      .with("connected", () => {
301→        _connectionId = msg.connectionId as string;
302→        connected = true;
303→        connecting = false;
304→        reconnectAttempt = 0;
305→
306→        // Re-subscribe all active subscriptions (reconnect scenario)
307→        resubscribeAll();
308→
309→        // Notify hooks that connection is available so they can set up subscriptions
310→        notifyConnectionChange(true);
311→
312→        connectResolve?.();
313→        connectResolve = null;
314→        connectReject = null;
315→      })
316→      .with("ping", () => {
317→        sendFrame({ type: "pong" });
318→      })
319→      .with("q:snapshot", () => {
320→        const sub = subscriptions.get(msg.id as string);
321→        sub?.onSnapshot(msg.data);
322→      })
323→      .with("q:delta", () => {
324→        const sub = subscriptions.get(msg.id as string);
325→        sub?.onDelta?.(
326→          msg.upserted as unknown[] | undefined,
327→          msg.removed as string[] | undefined,
328→          msg.cursor as number | undefined
329→        );
330→      })
331→      .with("q:command_ack", () => {
332→        const pending = pendingCommands.get(msg.id as string);
333→        if (pending) {
334→          pendingCommands.delete(msg.id as string);
335→          pending.resolve({
336→            accepted: msg.accepted as boolean,
337→            commandId: msg.commandId as string | undefined,
338→            error: msg.error as string | undefined,
339→          });
340→        }
341→      })
342→      .with("q:event", () => {
343→        const event = msg.event as string;
344→        const data = msg.data;
345→        for (const cb of eventListeners) {
346→          try {
347→            cb(event, data);
348→          } catch (err) {
349→            console.error("[WS] Event listener error:", err);
350→          }
351→        }
352→      })
353→      .with("q:error", () => {
354→        console.warn("[WS] Query error:", msg.message, "for sub:", msg.id);
355→      })
356→      .otherwise(() => {
357→        // Ignore unknown frame types (q:response, q:mutate_result, etc.)
358→      });
359→  };
360→
361→  ws.onerror = () => {
362→    // onerror fires before onclose — actual cleanup happens in onclose
363→  };
364→
365→  ws.onclose = () => {
366→    const wasConnected = connected;
367→    connected = false;
368→    _connectionId = null;
369→    ws = null;
370→
371→    // Reject all pending commands immediately — they can't succeed without a connection
372→    for (const [_id, pending] of pendingCommands) {
373→      pending.reject(new Error("WebSocket disconnected"));
374→    }
375→    pendingCommands.clear();
376→
377→    if (connecting) {
378→      // Initial connection failed — reject the connect() promise
379→      connecting = false;
380→      connectReject?.(new Error("WebSocket connection failed"));
381→      connectResolve = null;
382→      connectReject = null;
383→    }
384→
385→    if (wasConnected) {
386→      notifyConnectionChange(false);
387→    }
388→
389→    // Only auto-reconnect if we had previously connected or have active subscriptions
390→    if (wasConnected || subscriptions.size > 0) {
391→      scheduleReconnect();
392→    }
393→  };
394→}
395→
396→/** Notify all connection change listeners. */
397→function notifyConnectionChange(state: boolean): void {
398→  for (const cb of connectionChangeListeners) {
399→    try {
400→      cb(state);
401→    } catch (err) {
402→      console.error("[WS] Connection change listener error:", err);
403→    }
404→  }
405→}
406→
407→function sendFrame(frame: Record<string, unknown>): boolean {
408→  if (ws && ws.readyState === WebSocket.OPEN) {
409→    try {
410→      ws.send(JSON.stringify(frame));
411→      return true;
412→    } catch {
413→      // Connection may have closed between readyState check and send
414→      console.warn(`[WS] Failed to send ${frame.type} frame: connection closed during send`);
415→      return false;
416→    }
417→  }
418→  console.warn(`[WS] Dropped ${frame.type} frame: WebSocket not connected`);
419→  return false;
420→}
421→
422→/** Re-subscribe all active subscriptions after reconnect. */
423→function resubscribeAll(): void {
424→  for (const sub of subscriptions.values()) {
425→    sendFrame({
426→      type: "q:subscribe",
427→      id: sub.id,
428→      resource: sub.resource,
429→      ...(sub.params ? { params: sub.params } : {}),
430→    });
431→  }
432→}
433→
434→/** Schedule a reconnection with exponential backoff. */
435→function scheduleReconnect(): void {
436→  if (reconnectTimer) return;
437→
438→  const delay = Math.min(BACKOFF_BASE_MS * Math.pow(2, reconnectAttempt), BACKOFF_MAX_MS);
439→  reconnectAttempt++;
440→
441→  if (import.meta.env.DEV) {
442→    console.log(`[WS] Reconnecting in ${delay}ms (attempt ${reconnectAttempt})`);
443→  }
444→
445→  reconnectTimer = setTimeout(() => {
446→    reconnectTimer = null;
447→    connecting = true;
448→
449→    // Set up resolve/reject so subscriptions get re-established
450→    connectResolve = null;
451→    connectReject = null;
452→
453→    openSocket().catch(() => {
454→      connecting = false;
455→      // onclose handler will schedule another reconnect
456→    });
457→  }, delay);
458→}
