  1→/**
  2→ * Backend Process Manager
  3→ *
  4→ * Spawns the Node.js backend as a child process using ELECTRON_RUN_AS_NODE=1.
  5→ * Parses the dynamic port from stdout, generates an auth token, and handles
  6→ * exit/restart with exponential backoff.
  7→ *
  8→ * Uses child_process directly since we're already in Node.js.
  9→ */
 10→
 11→import { spawn, type ChildProcess } from "child_process";
 12→import { join } from "path";
 13→import { existsSync } from "fs";
 14→import { app, BrowserWindow } from "electron";
 15→import crypto from "crypto";
 16→
 17→let backendProcess: ChildProcess | null = null;
 18→let isQuitting = false;
 19→let restartAttempt = 0;
 20→let restartTimer: ReturnType<typeof setTimeout> | null = null;
 21→const MAX_RESTART_ATTEMPTS = 5;
 22→const STARTUP_TIMEOUT_MS = 30_000;
 23→
 24→export async function spawnBackend(): Promise<{ port: number; authToken: string }> {
 25→  const authToken = crypto.randomBytes(24).toString("hex");
 26→
 27→  // Resolve backend entry point
 28→  // Production: bundled CJS file (no tsx dependency needed)
 29→  // Development: server.cjs bootstraps tsx for live TypeScript
 30→  const backendEntry = app.isPackaged
 31→    ? join(process.resourcesPath, "backend", "server.bundled.cjs")
 32→    : join(__dirname, "../../backend/server.cjs");
 33→
 34→  // Database path — prefer legacy location (com.opendevs.ide) if it exists,
 35→  // otherwise use Electron's userData dir (~/Library/Application Support/opendevs/).
 36→  const legacyDbPath = join(app.getPath("appData"), "com.opendevs.ide", "opendevs.db");
 37→  const electronDbPath = join(app.getPath("userData"), "opendevs.db");
 38→  const dbPath = existsSync(legacyDbPath) ? legacyDbPath : electronDbPath;
 39→
 40→  // Sidecar bundle path
 41→  const sidecarPath = app.isPackaged
 42→    ? join(process.resourcesPath, "bin", "index.bundled.cjs")
 43→    : join(__dirname, "../../sidecar/dist/index.bundled.cjs");
 44→
 45→  // Notebook server bundle path
 46→  const notebookPath = app.isPackaged
 47→    ? join(process.resourcesPath, "bin", "notebook-server.bundled.cjs")
 48→    : join(__dirname, "../../packages/mcp-notebook/dist/notebook-server.bundled.cjs");
 49→
 50→  return new Promise((resolve, reject) => {
 51→    backendProcess = spawn(process.execPath, [backendEntry], {
 52→      cwd: app.isPackaged ? process.resourcesPath : join(__dirname, "../../backend"),
 53→      env: {
 54→        ...process.env,
 55→        ELECTRON_RUN_AS_NODE: "1",
 56→        DATABASE_PATH: dbPath,
 57→        SIDECAR_BUNDLE_PATH: sidecarPath,
 58→        NOTEBOOK_SERVER_BUNDLE_PATH: notebookPath,
 59→        AUTH_TOKEN: authToken,
 60→        PORT: "0", // Dynamic port allocation
 61→      },
 62→      stdio: ["ignore", "pipe", "pipe"],
 63→    });
 64→
 65→    let resolved = false;
 66→    let stdoutBuffer = "";
 67→
 68→    // Parse port from stdout
 69→    backendProcess.stdout?.on("data", (data: Buffer) => {
 70→      stdoutBuffer += data.toString();
 71→      const lines = stdoutBuffer.split("\n");
 72→      stdoutBuffer = lines.pop() ?? ""; // Keep incomplete last line in buffer
 73→      for (const line of lines) {
 74→        const trimmed = line.trim();
 75→        if (!trimmed) continue;
 76→
 77→        // Log backend stdout in dev mode
 78→        if (!app.isPackaged) {
 79→          console.log("[backend]", trimmed);
 80→        }
 81→
 82→        // Match both formats: "[BACKEND_PORT]12345" (primary) and
 83→        // "Backend server started on port 12345" (legacy fallback).
 84→        const portMatch =
 85→          trimmed.match(/^\[BACKEND_PORT\](\d+)$/) ||
 86→          trimmed.match(/Backend server started on port (\d+)/);
 87→        if (portMatch && !resolved) {
 88→          resolved = true;
 89→          restartAttempt = 0;
 90→          resolve({ port: parseInt(portMatch[1], 10), authToken });
 91→        }
 92→
 93→        // Relay workspace init progress events to the renderer.
 94→        // Backend emits: OPENDEVS_WORKSPACE_PROGRESS:{"workspaceId":"...","step":"...","label":"..."}
 95→        // We parse the JSON and forward it as an IPC event to the renderer.
 96→        // SYNC: Event name must match shared/events.ts (AppEventMap["workspace:progress"])
 97→        if (trimmed.startsWith("OPENDEVS_WORKSPACE_PROGRESS:")) {
 98→          const jsonStr = trimmed.slice("OPENDEVS_WORKSPACE_PROGRESS:".length);
 99→          try {
100→            const payload = JSON.parse(jsonStr);
101→            const win = BrowserWindow.getAllWindows()[0];
102→            if (win) {
103→              win.webContents.send("workspace:progress", payload);
104→            }
105→          } catch {
106→            // Ignore malformed progress lines
107→          }
108→        }
109→      }
110→    });
111→
112→    backendProcess.stderr?.on("data", (data: Buffer) => {
113→      console.error("[backend:stderr]", data.toString().trim());
114→    });
115→
116→    backendProcess.on("exit", (code, signal) => {
117→      console.log(`[backend] Exited with code=${code} signal=${signal}`);
118→      backendProcess = null;
119→
120→      if (!resolved) {
121→        reject(new Error(`Backend exited before starting (code=${code})`));
122→        return;
123→      }
124→
125→      // Restart with exponential backoff (unless app is quitting)
126→      if (!isQuitting && restartAttempt < MAX_RESTART_ATTEMPTS) {
127→        restartAttempt++;
128→        const delay = Math.min(1000 * Math.pow(2, restartAttempt - 1), 30_000);
129→        console.log(`[backend] Restart attempt ${restartAttempt} in ${delay}ms`);
130→        restartTimer = setTimeout(() => {
131→          restartTimer = null;
132→          spawnBackend()
133→            .then(({ port, authToken: newAuthToken }) => {
134→              // Update env vars so IPC handlers (native:getBackendPort) return the new port
135→              process.env.OPENDEVS_BACKEND_PORT = String(port);
136→              process.env.OPENDEVS_AUTH_TOKEN = newAuthToken;
137→
138→              // Notify all renderer windows so they can invalidate their cached port
139→              // and reconnect WebSocket to the new address.
140→              for (const win of BrowserWindow.getAllWindows()) {
141→                win.webContents.send("backend:port-changed", { port });
142→              }
143→              console.log(`[backend] Restarted on port ${port}, notified renderer`);
144→            })
145→            .catch((err) => {
146→              console.error("[backend] Restart failed:", err);
147→            });
148→        }, delay);
149→      }
150→    });
151→
152→    backendProcess.on("error", (err) => {
153→      console.error("[backend] Spawn error:", err);
154→      if (!resolved) {
155→        reject(err);
156→      }
157→    });
158→
159→    // Timeout if backend doesn't start
160→    setTimeout(() => {
161→      if (!resolved) {
162→        resolved = true;
163→        backendProcess?.kill("SIGTERM");
164→        reject(new Error(`Backend startup timeout (${STARTUP_TIMEOUT_MS}ms)`));
165→      }
166→    }, STARTUP_TIMEOUT_MS);
167→  });
168→}
169→
170→export function stopBackend(): void {
171→  isQuitting = true;
172→  if (restartTimer) {
173→    clearTimeout(restartTimer);
174→    restartTimer = null;
175→  }
176→  if (backendProcess) {
177→    backendProcess.kill("SIGTERM");
178→    // Force kill after 5s if graceful shutdown fails
179→    const forceTimer = setTimeout(() => {
180→      if (backendProcess) {
181→        backendProcess.kill("SIGKILL");
182→        backendProcess = null;
183→      }
184→    }, 5_000);
185→    backendProcess.on("exit", () => {
186→      clearTimeout(forceTimer);
187→      backendProcess = null;
188→    });
189→  }
190→}
