 16→// Helper to wait for a condition with timeout
 17→function waitFor(fn: () => boolean, timeoutMs = 5000): Promise<void> {
 18→  return new Promise((resolve, reject) => {
 19→    const start = Date.now();
 20→    const check = () => {
 21→      if (fn()) return resolve();
 22→      if (Date.now() - start > timeoutMs) return reject(new Error("waitFor timed out"));
 23→      setTimeout(check, 20);
 24→    };
 25→    check();
 26→  });
 27→}
 28→
 29→// Helper to collect messages from a socket
 30→function collectMessages(socket: net.Socket): unknown[] {
 31→  const messages: unknown[] = [];
 32→  let buffer = "";
 33→  const decoder = new StringDecoder("utf8");
 34→
 35→  socket.on("data", (data) => {
 36→    buffer += decoder.write(data);
 37→    const lines = buffer.split("\n");
 38→    buffer = lines.pop() || "";
 39→    for (const line of lines) {
 40→      if (line.trim()) {
 41→        try {
 42→          messages.push(JSON.parse(line));
 43→        } catch {
 44→          // ignore parse errors
 45→        }
 46→      }
 47→    }
 48→  });
 49→
 50→  return messages;
 51→}
